var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어떻게 된 거지? 냉기가 생각대로 움직이지 않아.","JPN":"どういうこと？　冷気が思いどおり動かせないわ。","ENG":"I do not understand... Why can I not use my frost powers?","TWN":"怎麼回事？寒氣不受控制。"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이제까지 이런 적은 한 번도 없었는데, 어째서……!","JPN":"今までこんなことなかったのに、どうして……！","ENG":"This has never happened once...! Why?!","TWN":"以前從來沒出現過這種情況，為什麼……！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"냉기를 두려워하지 마라! 다들 부학회장님을 붙잡아!","JPN":"冷気を恐れるな！　副学会長を捕らえろ！","ENG":"Don't fear the frost! Men, grab her!","TWN":"別怕她的寒氣！大家一起抓住副學會長！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_A","text":{"KOREA":"죄송합니다, 부학회장님!","JPN":"申し訳ございません、副学会長！","ENG":"I'm so sorry, Vice President!","TWN":"抱歉，副學會長！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L8_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이거 놓지 못해?! 어디 숙녀 손목을 함부로 잡아요!","JPN":"放しなさい！！　淑女の手首を掴むとは何事ですの！","ENG":"Let go! How dare you lay hands on a lady!!","TWN":"放開我？！是誰允許你們隨便抓住淑女的手腕的！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_C","text":{"KOREA":"한두 명으로는 역부족이다! 전원 가세해!","JPN":"一人二人だけでは足りない！　全員、加勢しろ！","ENG":"Two men aren't enough to hold her down! Everyone, grab her!","TWN":"一兩個人不夠！大家一起上！"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"자, 잠깐만요? 저 하나 붙잡자고 도대체 몇 명이…","JPN":"ちょ、ちょっと？　私一人捕まえるのに一体何人……","ENG":"W-wait! How many of you are coming to–","TWN":"等…等一下？為了抓住我，這麼多人一起上也……"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L11_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"꺄악!?","JPN":"きゃあっ！？","ENG":"Kyaah!","TWN":"哎呀！？"},"stage":{"bg":"CORRIDOR_06","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"세상에, 부학회장님….","JPN":"まあ、副学会長様……","ENG":"Oh dear, Vice President...","TWN":"天啊，副學會長……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SILKY_NPC_ESPR2_NULL","text":{"KOREA":"부학회장님이 힘들어하시잖아요! 어서 놓아 주세요!","JPN":"副学会長様が痛がってらっしゃるじゃないですか！　早くお放しください！","ENG":"Can't you see you're stressing her?! Let go of her!","TWN":"副學會長很難受！快點放開她！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SILKY_NPC_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"시끄럽다. 영지에서 따라온 주민 같은데, 지금 학회 일에 끼어들겠다는 건가?","JPN":"うるさい。領地からついてきた住民のようだが、学会のことに口を挟む気か？","ENG":"Silence. You look like a resident from the estate, and are you trying to interfere with Society business?","TWN":"閉嘴。你是從領地過來的居民吧，現在想插手學會的事嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"그대로 침실로 모셔라. 조금 불편해하셔도 상관없다.","JPN":"そのまま寝室にお連れしろ。少々ご不満を訴えられるかもしれないが、構わない。","ENG":"Take her to her bed. Be a little rough if you have to.","TWN":"直接送回臥室。有點不舒服也沒關係。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"조금이 아니라 많이 불편하다고요!","JPN":"少々どころか大いに不満ですわ！","ENG":"You call this a little? You are practically crushing me!","TWN":"不是有點，是非常不舒服！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"묻는 말엔 입 꾹 다물고 자기 할말만 하면 다야?! 대답 못하겠으면 에델이라도 데려와요!","JPN":"私の問いには口を固く閉ざして、そちらの言いたいことだけ言うのですか！？　答えられないのならエデルでも連れてきなさい！","ENG":"You ignore my questions and only say what you need?! If you cannot answer me, bring Edel to me!","TWN":"對我的問話拒不回答，只願意說自己想說的話嗎？！如果答不上來，就帶艾瑟兒過來！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_QM","text":{"KOREA":"뭐야, 뭐야? 왜 이리 시끄러워? 나 빼놓고 파티 연 거 아니지?","JPN":"なになに？　なんでこんなに騒がしいの？　アタシだけのけ者にしてパーティーでもしてるんじゃないよね？","ENG":"Huh? What's going on here? What's all the ruckus about? Are you all having a party without me?","TWN":"怎麼回事，怎麼回事？為什麼這麼吵？不會背著我開派對吧？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_QM","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L24_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"아. 오셨군요. 루나 님.","JPN":"あ。おいででしたか。ルナ様。","ENG":"Oh, you're here, Ms. Luna.","TWN":"啊，你來了，露娜。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"부학회장님을 침실로 모시는 과정에서 조금 문제가 생겼습니다.","JPN":"副学会長を寝室にお連れしようとしましたが、少々問題が発生しまして。","ENG":"We ran into slight trouble while escorting Ms. Vice President to her room.","TWN":"我們在請副學會長回臥室，這個過程中發生了一點小問題。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"호오, 그럼 밖으로 나가려고 했다는 뜻이네.","JPN":"ほう、じゃあ外に出ようとしたってことだね。","ENG":"Ho-oh, then that means she tried to get out, no?","TWN":"喔呵，意思是她想去外面吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"잘했어. 앞으로 비슷한 일 생기면 바로 나한테 보고해.","JPN":"よくやった。今度このようなことがあればすぐアタシに報告して。","ENG":"Good job. Report back to me immediately when something like this happens again.","TWN":"做得好。以後再發生類似的事，馬上向我報告。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"당신은 누구죠? 아직 어린애 같은데 학회원인가요?","JPN":"あなたはどなたですの？　まだ子どものようですが、学会員ですの？","ENG":"Who are you? Are you also a member of the Society? But you look so young, kid.","TWN":"你是誰？好像還是個小孩子，是學會成員嗎？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"누가 누구더러 꼬맹이래? 흥이다, 메~롱!","JPN":"誰が誰に向かって子ども呼ばわり？　ふん、べーっだ！","ENG":"Hey, who're you calling a kid?! Hmph! Rude, much?!","TWN":"你說誰是小孩子？哼，ㄌㄩㄝ～"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"난 루나! 엘리시움 필하모닉 최고의 나팔수이자 여기 책임자라구!","JPN":"アタシはルナ！　エリシウムフィルハーモニーの首席トランぺット奏者で、ここの責任者なんだから！","ENG":"My name is Luna! The best trumpeter in Elysium Philharmonic and the supervisor of this place!","TWN":"我是露娜！愛樂組織的首席小號手，也是這裡的負責人！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"좋아요. 따지고 싶은 점이 한두 가지가 아니지만 일단 넘어가겠습니다.","JPN":"いいでしょう。問い詰めたいことは山ほどありますが、ここは一旦収めましょう。","ENG":"All right. I have several points I would like to make, but I will leave them for now.","TWN":"好吧。雖然我有很多問題想問，不過都暫時略過吧。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"길게 말하고 싶은 생각 없어요. 우선 제 위에 올라타 있는 학회원들부터 치워 주세요.","JPN":"多くは言いません。まず私を押さえつけている学会員からどくように言ってください。","ENG":"I have no intention of exchanging words with you long. But first, get these hooligans off of me.","TWN":"我不想說太多。麻煩你先把我身上的這些學會成員弄走。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"싫~어. 내가 왜?","JPN":"やだ。なんでいうこと聞かなきゃならないの？","ENG":"No. Why would I do that?","TWN":"不～要。我為什麼要那麼做？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"뭐라고요?","JPN":"何ですって？","ENG":"Excuse me?","TWN":"你說什麼？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"응? 설마 잊어 먹었어?","JPN":"え？　まさか忘れちゃたの？","ENG":"Hmm? Wait, did you forget?","TWN":"嗯？你難道忘了？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"자, 이건 학회에서 보낸 편지야. 읽어 줄 테니까 잘 들으라구.","JPN":"ほら、これが学会から送られてきた手紙。読んであげるからよく聞くことね。","ENG":"Here. This is a letter from the Society. I'll read it out loud for you, so listen closely.","TWN":"來，這是學會寄來的信。我念給你聽聽。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"흠. 흠.","JPN":"ゴホン、ゴホン。","ENG":"Ahem!","TWN":"咳，咳。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>호텔 아르마다 1408호 상주 학회원 일동에게.\\n아래 신설된 규정을 숙지하고 준수하여 주시기 바랍니다.</color>","JPN":"<color=#ffd34c>ホテルアルマダ1408号に常住する学会員一同へ。\\n下記の新設された規定を熟知し、順守するようにお願いします。</color>","ENG":"<color=#ffd34c>To all Society members residing in Hotel Armada room 1408.\\nPlease familiarize yourself with the new regulations listed below.</color>","TWN":"<color=#ffd34c>致艾魯瑪達飯店1408號全體常駐學會成員，\\n請熟知並遵守以下新規定。</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L42_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>1. 레지나 맥크레디(이하 투숙객)는 요양 기간 동안 객실 밖으로 나와서는 안 된다.</color>","JPN":"<color=#ffd34c>1. レジーナ・マクレディー(以下、宿泊客)を療養期間中に客室の外に出してはならない。</color>","ENG":"<color=#ffd34c>1. Regina MacCready (hereinafter referred to as \\"the guest\\") shall not be permitted to leave her room during her recuperation.</color>","TWN":"<color=#ffd34c>1. 蕾佳娜·麥克蕾蒂（以下稱“房客”）休養期間不得走出客房。</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L43_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>2. 침실 출입문은 24시간 2명 이상의 상주 학회원이 배치되어 출입을 통제할 것.</color>","JPN":"<color=#ffd34c>2. 寝室の出入口は常時2名以上の常住学会員を配置し、出入りを統制すること。</color>","ENG":"<color=#ffd34c>2. The room must be guarded by at least 2 Society members at all times.</color>","TWN":"<color=#ffd34c>2. 臥室門口安排兩名以上常駐學會成員，需要24小時值班，禁止房客進出。</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L44_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>3. 투숙객에게는 투입구를 통해 8시간 간격으로 각각 다른 식단을 제공할 것.</color>","JPN":"<color=#ffd34c>3. 宿泊客には投入口から8時間おきに異なるメニューの食事を提供すること。</color>","ENG":"<color=#ffd34c>3. Meals will be served 8 hours apart, with a different meal each time, through the meal slot.</color>","TWN":"<color=#ffd34c>3. 透過投放口，每隔8小時給房客提供不同的食物。</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L45_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>4. 책임자 외 모든 상주 학회원은 투숙객과의 대화가 제한된다. 상세 항목은 동봉된 문서를 참고할 것.</color>","JPN":"<color=#ffd34c>4. 責任者以外のすべての常住学会員は宿泊客との会話を制限する。詳細項目は同封の文書参照。</color>","ENG":"<color=#ffd34c>4. All Society members other than the supervisor are not allowed to talk with guests. Please see the attached document for details.</color>","TWN":"<color=#ffd34c>4. 除負責人外，所有常駐學會成員均不得與房客交談。詳細內容請參考附件。</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L46_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>5. 상주 학회원을 공격하거나 직권으로 통제하는 경우, 물리력을 사용해 필히 제압할 것.</color>","JPN":"<color=#ffd34c>5. 宿泊客が常住学会員を攻撃したり職権で統制する場合、物理力を行使し必ず制圧すること。</color>","ENG":"<color=#ffd34c>5. If the guest attempts to attack a member or usurp her authority, she can be physically subdued.</color>","TWN":"<color=#ffd34c>5. 房客攻擊常駐學會成員，或用職權控制學會成員時，可以使用武力制服。</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L47_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>위 규정은 다음 서명인의 인가 하에 효력을 발휘합니다.</color>","JPN":"<color=#ffd34c>上記規定は次の署名人の承認により効力を発するものとする。</color>","ENG":"<color=#ffd34c>The above shall become effective upon the authorization of the signer.</color>","TWN":"<color=#ffd34c>以上規定在以下簽名人的批准下生效。</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L48_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>에크하르트 초월지식 학회 부학회장 레지나 맥크레디.</color>","JPN":"<color=#ffd34c>エクハルト超越知識学会　副学会長　レジーナ・マクレディー</color>","ENG":"<color=#ffd34c>Vice President of Eckhart's Society for Preternatural Research, Regina MacCready.</color>","TWN":"<color=#ffd34c>埃克哈特超越學會副學會長，蕾佳娜·麥克蕾蒂。</color>"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_09"},{"id":"L50_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"서명인…… 레지나 맥크레디?","JPN":"署名人……レジーナ・マクレディー？","ENG":"The signer is... Regina MacCready?","TWN":"簽名人……是蕾佳娜·麥克蕾蒂？"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"말도 안 돼. 정말 내 서명이잖아…….","JPN":"そんな……本当に私のサインだわ……","ENG":"This is ridiculous! That is my signature...","TWN":"不可能。真是我的簽名……"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"이제 알겠지? 우린 그냥 언니가 해 달라는 대로 해 주는 거야.","JPN":"わかったでしょ？　アタシたちはあんたからの頼みどおりにしてやってるんだよ。","ENG":"Do you get it now? We're just doing as you told.","TWN":"現在你知道了吧？我們是在按照姊姊的要求執行。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"내가 왔을 때 부학회장님은 이미 침실에 콕 박혀 있었다구.","JPN":"アタシが来た時にはすでに副学会長様は寝室に引きこもってたもん。","ENG":"When I arrived here, you were already locked up in your room.","TWN":"我來的時候，副學會長已經在臥室裡了。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"순 억지야! 조작된 편지가 분명해요!","JPN":"何かの間違いですわ！　でっち上げられた手紙に違いありません！","ENG":"Impossible! That letter must have been forged!","TWN":"怎麼可能！這封信肯定是偽造的！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이상하다는 생각 안 들어요? 자기가 자기를 가두는 사람이 세상에 어디 있어요?!","JPN":"おかしいと思わないのですか？　自分で自分を閉じ込める人など、どこにいるのですか！？","ENG":"Do you not find it strange? Who in the world would ever want to lock herself up?!","TWN":"你不覺得奇怪嗎？世界上怎麼可能有人要求把自己關起來？！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"있는데? 그것도 지금 내 바로 앞에.","JPN":"いるじゃない？　今アタシの目の前に。","ENG":"What do you mean? I'm looking right at her.","TWN":"當然有啊？現在不就站在我面前嗎。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러니까, 그게……!","JPN":"ですから、それは……！","ENG":"That's not what I mea–!","TWN":"所以，那個……！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"아—. 몰라 몰라.","JPN":"あ～、もうどっちだっていいよ。","ENG":"Ugh, I don't wanna hear it.","TWN":"啊——我不管，我不管。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"나라고 뭐 따분하게 방구석이나 감시하고 싶은 줄 알아? 다 시키니까 하는 거지.","JPN":"部屋の監視なんていうつまんないこと、誰がやりたいと思う？　仕事だから仕方なくやってるんだ。","ENG":"Do you think I enjoy mindlessly observing you? I'm only doing it because you told me to.","TWN":"你以為我想無聊地監視房間嗎？都是因為命令，我才做的。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"TRUMPET_HARMONY_ESPR2_NULL","text":{"KOREA":"집어 넣어. 다시 못 나오게 방문에 자물쇠 채우는 거 잊지 마.","JPN":"ぶち込んで。二度と出られないようにドアにカギかけるの忘れないでね。","ENG":"Get her back in. And don't forget to lock the door so she doesn't try escaping again.","TWN":"讓她進去。別忘了鎖上房門，不能讓她再出來。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DOCTOR_NPC_ESPR2_B","text":{"KOREA":"네. 조치하겠습니다.","JPN":"はい。対処いたします。","ENG":"Yes, ma'am.","TWN":"是的，馬上執行。"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TRUMPET_HARMONY_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DOCTOR_NPC_ESPR2_B","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"놔요!! 놓으라는 말 안 들려요!? 이봐요!! 야!","JPN":"放しなさい！！　放せと言ってるのが聞こえないのですか！？　ちょっと！！　あなた！","ENG":"LET GO!! Did you not hear me?! Hey! HEYYY!!!","TWN":"放開我！！沒聽見我說的話嗎！？放開我！！喂！"},"stage":{"bg":"CORRIDOR_06","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DOCTOR_NPC_ESPR2_C","face":"UNIT_IDLE"},"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"DOCTOR_NPC_ESPR2_A","face":"UNIT_IDLE"}}}}]`);export{e as default};